// Package imports:
import 'package:flutter_test/flutter_test.dart';

// Project imports:
import 'package:baseball_detector_flutter/data/models/item.dart';
import 'package:baseball_detector_flutter/data/models/plan.dart';
import 'package:baseball_detector_flutter/data/models/team.dart';
import 'package:baseball_detector_flutter/data/models/team_plan.dart';
import 'package:baseball_detector_flutter/data/models/utils/now_provider.dart';

// ========================================
// テストヘルパー関数
// ========================================

/// 共通で使用する定数
const id = '00000000-0000-4000-8000-000000000000';
const teamPlanId = '77777777-0003-0001-0000-000000000001';
const teamPlanId2 = '77777777-0003-0001-0000-000000000002';
const name = 'test name';
const ownerUserId = '00000000-0000-4000-8000-000000000001';
const imageUrl = 'https://example.test/image.jpg';
const presignedImageUrl = 'https://example.test/image.jpg?presigned';

/// テストで使用する日時を返す
DateTime now() => DateTime.now();
DateTime createdAt() => now().subtract(const Duration(days: 1));
DateTime updatedAt() => now().subtract(const Duration(days: 1));

/// 標準的な Plan を作成
Plan createPlan({
  String planId = '2',
  String planName = 'Test plan',
  int maxBalls = 100,
  int maxAiCoachs = 50,
}) {
  return Plan(
    id: planId,
    name: planName,
    description: 'Test description',
    type: 1,
    maxBalls: maxBalls,
    maxAiCoachs: maxAiCoachs,
    createdAt: createdAt(),
    updatedAt: updatedAt(),
  );
}

/// TeamPlan を作成
TeamPlan createTeamPlan({
  String? id = teamPlanId,
  String? teamId = id,
  String planId = '2',
  DateTime? startDate,
  DateTime? endDate,
  int currentUsage = 0,
  int currentAiCoachUsage = 0,
  bool isActive = true,
  bool isPendingActivation = false,
  Plan? plan,
}) {
  return TeamPlan(
    id: id,
    teamId: teamId,
    planId: planId,
    startDate: startDate ?? now().subtract(const Duration(days: 10)),
    endDate: endDate ?? now().add(const Duration(days: 40)),
    currentUsage: currentUsage,
    currentAiCoachUsage: currentAiCoachUsage,
    isActive: isActive,
    isPendingActivation: isPendingActivation,
    createdAt: createdAt(),
    updatedAt: updatedAt(),
    plan: plan,
  );
}

/// Team を作成
Team createTeam({
  String? teamId = id,
  String? teamName = name,
  String? ownerId = ownerUserId,
  TeamPlan? teamPlan,
  TeamPlan? nextTeamPlan,
  Item? item,
}) {
  return Team(
    id: teamId,
    name: teamName,
    ownerUserId: ownerId,
    createdAt: createdAt(),
    updatedAt: updatedAt(),
    imageUrl: imageUrl,
    teamPlan: teamPlan,
    nextTeamPlan: nextTeamPlan,
    presignedImageUrl: presignedImageUrl,
    item: item,
  );
}

// ========================================
// テストケース
// ========================================

void main() {
  group('Testing Team', () {
    final fixedCreatedAt = DateTime(2024, 1, 1, 0, 0);
    final fixedUpdatedAt = DateTime(2024, 1, 1, 1, 0);
    const item = Item(
      aiCoachUsage: 1,
      ballUsage: 10,
      aiCoachAvailableCount: 5,
      ballAvailableCount: 50,
    );
    final teamPlan = TeamPlan(
      id: teamPlanId,
      teamId: '00000000-0000-4000-8000-000000000000',
      planId: '2',
      startDate: DateTime.utc(2023, 1, 1, 0, 0),
      endDate: DateTime.utc(2024, 1, 1, 0, 0),
      currentUsage: 0,
      currentAiCoachUsage: 0,
      isActive: true,
      isPendingActivation: false,
      createdAt: fixedCreatedAt,
      updatedAt: fixedUpdatedAt,
      plan: null,
    );
    final nextTeamPlan = TeamPlan(
      id: teamPlanId2,
      teamId: '00000000-0000-4000-8000-000000000001',
      planId: '3',
      startDate: DateTime.utc(2024, 1, 1, 0, 0),
      endDate: DateTime.utc(2025, 1, 1, 0, 0),
      isPendingActivation: false,
      currentUsage: 0,
      currentAiCoachUsage: 0,
      isActive: true,
      createdAt: fixedCreatedAt,
      updatedAt: fixedUpdatedAt,
      plan: null,
    );

    test('toJson1', () {
      final team = Team(
        id: id,
        name: name,
        ownerUserId: ownerUserId,
        createdAt: fixedCreatedAt,
        updatedAt: fixedUpdatedAt,
        imageUrl: imageUrl,
        teamPlan: teamPlan,
        nextTeamPlan: nextTeamPlan,
        presignedImageUrl: presignedImageUrl,
        item: item,
      );

      final teamJson = team.toJson();

      expect(teamJson.length, 15);
      expect(teamJson.containsKey('id'), isTrue);
      expect(teamJson.containsKey('name'), isTrue);
      expect(teamJson.containsKey('ownerUserId'), isTrue);
      expect(teamJson.containsKey('createdAt'), isTrue);
      expect(teamJson.containsKey('updatedAt'), isTrue);
      expect(teamJson.containsKey('imageUrl'), isTrue);
      expect(teamJson.containsKey('teamPlan'), isTrue);
      expect(teamJson.containsKey('nextTeamPlan'), isTrue);
      expect(teamJson.containsKey('presignedImageUrl'), isTrue);
      expect(teamJson.containsKey('item'), isTrue);

      expect(teamJson['id'], id);
      expect(teamJson['name'], name);
      expect(teamJson['ownerUserId'], ownerUserId);
      expect(teamJson['createdAt'], fixedCreatedAt.toIso8601String());
      expect(teamJson['updatedAt'], fixedUpdatedAt.toIso8601String());
      expect(teamJson['imageUrl'], imageUrl);
      expect(teamJson['teamPlan'], teamPlan.toJson());
      expect(teamJson['nextTeamPlan'], nextTeamPlan.toJson());
      expect(teamJson['presignedImageUrl'], presignedImageUrl);
      expect(teamJson['item'], item.toJson());

      final deserializedTeam = Team.fromJson(teamJson);
      expect(deserializedTeam, team);
    });

    test('fromJson1 (API New)', () {
      final teamJson = {
        'id': id,
        'name': name,
        'ownerUserId': ownerUserId,
        'createdAt': fixedCreatedAt.toIso8601String(),
        'updatedAt': fixedUpdatedAt.toIso8601String(),
        'imageUrl': imageUrl,
        'teamPlan': {
          'id': teamPlan.id,
          'teamId': teamPlan.teamId,
          'planId': teamPlan.planId,
          'startDate': teamPlan.startDate!.toIso8601String(),
          'endDate': teamPlan.endDate!.toIso8601String(),
          'currentUsage': teamPlan.currentUsage,
          'currentAiCoachUsage': teamPlan.currentAiCoachUsage,
          'isActive': teamPlan.isActive,
          'isPendingActivation': teamPlan.isPendingActivation,
          'createdAt': teamPlan.createdAt!.toIso8601String(),
          'updatedAt': teamPlan.updatedAt!.toIso8601String(),
          'plan': null,
          'appleSubscription': null,
          'stripeSubscription': null,
        },
        'nextTeamPlan': {
          'id': nextTeamPlan.id,
          'teamId': nextTeamPlan.teamId,
          'planId': nextTeamPlan.planId,
          'startDate': nextTeamPlan.startDate!.toIso8601String(),
          'endDate': nextTeamPlan.endDate!.toIso8601String(),
          'currentUsage': nextTeamPlan.currentUsage,
          'currentAiCoachUsage': teamPlan.currentAiCoachUsage,
          'isActive': nextTeamPlan.isActive,
          'isPendingActivation': nextTeamPlan.isPendingActivation,
          'createdAt': nextTeamPlan.createdAt!.toIso8601String(),
          'updatedAt': nextTeamPlan.updatedAt!.toIso8601String(),
          'plan': null,
          'appleSubscription': null,
          'stripeSubscription': null,
        },
        'presignedImageUrl': presignedImageUrl,
        'teamType': 'multiple',
        'teamPlanCancelAt': null,
        'teamPlanDowngradeAt': null,
        'billingFailureReason': null,
        'downgradePlanId': null,
        'item': item.toJson(),
      };

      final team = Team.fromJson(teamJson);

      expect(team.id, id);
      expect(team.name, name);
      expect(team.ownerUserId, ownerUserId);
      expect(team.createdAt, fixedCreatedAt);
      expect(team.updatedAt, fixedUpdatedAt);
      expect(team.imageUrl, imageUrl);
      expect(team.teamPlan, teamPlan);
      expect(team.nextTeamPlan, nextTeamPlan);
      expect(team.presignedImageUrl, presignedImageUrl);
      expect(team.item, item);

      final serializedJson = team.toJson();
      expect(serializedJson, teamJson);
    });
  });

  test('fromJson2 (API Old)', () {
    const oldTeamPlanId = 1;
    const oldNextTeamPlanId = 2;
    final fixedCreatedAt = DateTime(2024, 1, 1, 0, 0);
    final fixedUpdatedAt = DateTime(2024, 1, 1, 1, 0);
    final teamPlan = TeamPlan(
      id: teamPlanId,
      teamId: '00000000-0000-4000-8000-000000000000',
      planId: '2',
      startDate: DateTime.utc(2023, 1, 1, 0, 0),
      endDate: DateTime.utc(2024, 1, 1, 0, 0),
      currentUsage: 0,
      currentAiCoachUsage: 0,
      isActive: true,
      isPendingActivation: false,
      createdAt: fixedCreatedAt,
      updatedAt: fixedUpdatedAt,
      plan: null,
    );
    final nextTeamPlan = TeamPlan(
      id: teamPlanId2,
      teamId: '00000000-0000-4000-8000-000000000001',
      planId: '3',
      startDate: DateTime.utc(2024, 1, 1, 0, 0),
      endDate: DateTime.utc(2025, 1, 1, 0, 0),
      isPendingActivation: false,
      currentUsage: 0,
      currentAiCoachUsage: 0,
      isActive: true,
      createdAt: fixedCreatedAt,
      updatedAt: fixedUpdatedAt,
      plan: null,
    );
    final teamJson = {
      'id': id,
      'name': name,
      'ownerUserId': ownerUserId,
      'createdAt': fixedCreatedAt.toIso8601String(),
      'updatedAt': fixedUpdatedAt.toIso8601String(),
      'imageUrl': imageUrl,
      'teamPlan': {
        'id': oldTeamPlanId,
        'teamId': teamPlan.teamId,
        'planId': teamPlan.planId,
        'startDate': teamPlan.startDate!.toIso8601String(),
        'endDate': teamPlan.endDate!.toIso8601String(),
        'currentUsage': teamPlan.currentUsage,
        'currentAiCoachUsage': teamPlan.currentAiCoachUsage,
        'isActive': teamPlan.isActive,
        'isPendingActivation': teamPlan.isPendingActivation,
        'createdAt': teamPlan.createdAt!.toIso8601String(),
        'updatedAt': teamPlan.updatedAt!.toIso8601String(),
        'plan': null,
        'appleSubscription': null,
        'stripeSubscription': null,
      },
      'nextTeamPlan': {
        'id': oldNextTeamPlanId,
        'teamId': nextTeamPlan.teamId,
        'planId': nextTeamPlan.planId,
        'startDate': nextTeamPlan.startDate!.toIso8601String(),
        'endDate': nextTeamPlan.endDate!.toIso8601String(),
        'currentUsage': nextTeamPlan.currentUsage,
        'currentAiCoachUsage': teamPlan.currentAiCoachUsage,
        'isActive': nextTeamPlan.isActive,
        'isPendingActivation': nextTeamPlan.isPendingActivation,
        'createdAt': nextTeamPlan.createdAt!.toIso8601String(),
        'updatedAt': nextTeamPlan.updatedAt!.toIso8601String(),
        'plan': null,
        'appleSubscription': null,
        'stripeSubscription': null,
      },
      'presignedImageUrl': presignedImageUrl,
      'teamType': 'multiple',
      'teamPlanCancelAt': null,
      'teamPlanDowngradeAt': null,
      'billingFailureReason': null,
      'downgradePlanId': null,
      'users': null,
    };

    final team = Team.fromJson(teamJson);

    expect(team.id, id);
    expect(team.name, name);
    expect(team.ownerUserId, ownerUserId);
    expect(team.createdAt, fixedCreatedAt);
    expect(team.updatedAt, fixedUpdatedAt);
    expect(team.imageUrl, imageUrl);
    expect(team.teamPlan, teamPlan.copyWith(id: oldTeamPlanId.toString()));
    expect(team.nextTeamPlan,
        nextTeamPlan.copyWith(id: oldNextTeamPlanId.toString()));
    expect(team.presignedImageUrl, presignedImageUrl);
    expect(team.item, isNull);

    final serializedJson = team.toJson();
    expect(serializedJson['item'], isNull);
    final serializedJsonWithoutItem = Map.of(serializedJson)..remove('item');
    expect(serializedJsonWithoutItem, teamJson);
  });

  group('TeamPlanStatus', () {
    final testNow = DateTime.now();
    final testPlan = createPlan();

    setUp(() {
      overrideTeamPlanNow(() => testNow);
    });

    tearDown(resetTeamPlanNow);

    test('expired: 期限切れ', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          endDate: testNow.subtract(const Duration(days: 1)),
          plan: testPlan,
        ),
      );
      expect(team.teamPlanStatus, TeamPlanStatus.expired);
    });

    test('ok: 正常', () {
      final team = createTeam(
        teamPlan: createTeamPlan(
          endDate: testNow.add(const Duration(days: 40)),
          currentUsage: 10,
