      );
      expect(team.teamPlanStatus, TeamPlanStatus.ok);
    });

    test(
        'expiringSoon: nextTeamPlan の startDate が teamPlan の endDate と一致していない場合で plan が有効',
        () {
      final team = Team(
        id: id,
